// ========================================
// WF2 v5 - VALIDATE & EXTRACT DATA
// Multi-level parsing + validation
// ========================================

const input = $input.first().json;

console.log('[WF2 v5] ==========================================');
console.log('[WF2 v5] Processing form submission');

// ==========================================
// MULTI-LEVEL PAYLOAD PARSING
// ==========================================
let data = null;
let parseSource = 'unknown';

// Level 1: FLAT structure (v4 Apps Script)
if (input.body?.clarificationId) {
  data = input.body;
  parseSource = 'input.body (FLAT)';
}
// Level 2: Nested in data
else if (input.body?.data?.clarificationId) {
  data = input.body.data;
  parseSource = 'input.body.data';
}
// Level 3: Double nested
else if (input.body?.body?.data?.clarificationId) {
  data = input.body.body.data;
  parseSource = 'input.body.body.data';
}
// Level 4: Direct body without data wrapper
else if (input.body?.body?.clarificationId) {
  data = input.body.body;
  parseSource = 'input.body.body';
}
// Level 5: Direct at root
else if (input.clarificationId) {
  data = input;
  parseSource = 'input (root)';
}

if (!data) {
  console.log('[WF2 v5] ERROR: Could not parse payload');
  console.log('[WF2 v5] Input structure:', JSON.stringify(input).substring(0, 500));
  return {
    json: {
      isValid: false,
      isTest: false,
      errors: ['Could not parse payload - no clarificationId found'],
      parseSource: 'FAILED',
      rawInput: JSON.stringify(input).substring(0, 200)
    }
  };
}

console.log('[WF2 v5] Parse source:', parseSource);

// ==========================================
// CHECK FOR TEST PAYLOAD
// ==========================================
const isTest = data._isTest === true || 
               (data.clarificationId && data.clarificationId.startsWith('TEST-'));

if (isTest) {
  console.log('[WF2 v5] Test payload detected - will skip task creation');
}

// ==========================================
// EXTRACT & VALIDATE FIELDS
// ==========================================
const clarificationId = data.clarificationId || '';
const nguonChiDao = data.nguonChiDao || '';
const ngayNhanChiDao = data.ngayNhanChiDao || '';
const noiDungGoc = data.noiDungGoc || '';
const dauMoiT1 = data.dauMoiT1 || '';
const t2NhiemVu = data.t2NhiemVu || '';
const t3ChiTieu = data.t3ChiTieu || '';
const t4ThoiHan = data.t4ThoiHan || '';
const ghiChu = data.ghiChu || '';
const xacNhan = data.xacNhan === true || data.xacNhan === 'true' || 
                (typeof data.xacNhan === 'string' && data.xacNhan.includes('xác nhận'));
const respondentEmail = data.respondentEmail || 'anonymous';
const formResponseId = data.formResponseId || '';

console.log('[WF2 v5] Fields extracted:');
console.log('  clarificationId:', clarificationId.substring(0, 20) + '...');
console.log('  dauMoiT1:', dauMoiT1);
console.log('  t2NhiemVu:', t2NhiemVu.substring(0, 30) + '...');
console.log('  t3ChiTieu:', t3ChiTieu.substring(0, 30) + '...');
console.log('  t4ThoiHan:', t4ThoiHan);
console.log('  xacNhan:', xacNhan);

// ==========================================
// VALIDATION
// ==========================================
const errors = [];

if (!clarificationId || clarificationId.length < 10) {
  errors.push('Thiếu Mã Clarification');
}
if (!t2NhiemVu || t2NhiemVu.length < 3) {
  errors.push('Thiếu T2 - Nhiệm vụ');
}
if (!t3ChiTieu || t3ChiTieu.length < 3) {
  errors.push('Thiếu T3 - Chỉ tiêu');
}
if (!t4ThoiHan) {
  errors.push('Thiếu T4 - Thời hạn');
}
if (!xacNhan) {
  errors.push('Chưa xác nhận');
}

const isValid = errors.length === 0;

console.log('[WF2 v5] Validation:', isValid ? '✅ PASSED' : '❌ FAILED');
if (!isValid) {
  console.log('[WF2 v5] Errors:', errors.join(', '));
}

// ==========================================
// DETERMINE MISSING TAGS TO CLEAR
// ==========================================
// Nếu đủ 4T thì clear hết, nếu thiếu thì để lại tags tương ứng
let missingTags = [];
if (!dauMoiT1) missingTags.push('Thiếu T1-TÊN');
if (!t2NhiemVu) missingTags.push('Thiếu T2-NHIỆM VỤ');
if (!t3ChiTieu) missingTags.push('Thiếu T3-CHỈ TIÊU');
if (!t4ThoiHan) missingTags.push('Thiếu T4-THỜI HẠN');

const has4T = missingTags.length === 0;

// ==========================================
// PREPARE HR SEARCH KEYWORDS
// ==========================================
// Extract search keywords from T1
// "HR Vy" → "Vy"
// "Thanh Hiếu" → "Hiếu"
// "Nhóm MSA" → "MSA"
let hrSearchKeyword = '';
if (dauMoiT1) {
  // Remove common prefixes
  hrSearchKeyword = dauMoiT1
    .replace(/^(HR|Nhóm|Ms\.?|Mr\.?)\s*/i, '')
    .trim();

  // If still has multiple words, take the last one (usually the given name)
  const words = hrSearchKeyword.split(/\s+/);
  if (words.length > 1) {
    hrSearchKeyword = words[words.length - 1];
  }
}

console.log('[WF2 v5] HR Search keyword:', hrSearchKeyword);

return {
  json: {
    isValid,
    isTest,
    errors,
    parseSource,

    // Form data
    clarificationId,
    nguonChiDao,
    ngayNhanChiDao,
    noiDungGoc,
    dauMoiT1,
    t2NhiemVu,
    t3ChiTieu,
    t4ThoiHan,
    ghiChu,
    xacNhan,
    respondentEmail,
    formResponseId,

    // Computed
    has4T,
    missingTags,
    hrSearchKeyword,
    today: new Date().toISOString().split('T')[0]
  }
};

// Extract HR info from search result
const formData = $('IF: Có T1?').first().json;
const searchResult = $input.first().json;

let hrId = '';
let hrEmail = '';
let hrName = '';
let hrFound = false;

try {
  const results = searchResult.results || [];
  if (results.length > 0) {
    const hr = results[0];
    hrId = hr.id;
    hrEmail = hr.properties?.['Email']?.email || '';
    hrName = hr.properties?.['Họ và Tên']?.title?.[0]?.plain_text || '';
    hrFound = true;
    console.log('[WF2 v5] HR Found:', hrName, '-', hrEmail);
  } else {
    console.log('[WF2 v5] HR Not found for keyword:', formData.hrSearchKeyword);
  }
} catch (e) {
  console.log('[WF2 v5] Error parsing HR result:', e.message);
}

return {
  json: {
    ...formData,
    hrId,
    hrEmail,
    hrName,
    hrFound
  }
};

// No HR search - pass through
const formData = $('IF: Có T1?').first().json;

return {
  json: {
    ...formData,
    hrId: '',
    hrEmail: '',
    hrName: '',
    hrFound: false
  }
};

